// ── Concurrency Guard ──
// Passes a run timestamp downstream.
// Real concurrency locking should use a dedicated lock row in Sheets
// or an external KV store (Redis). For now, 'Processing' status filter
// in node 01 prevents re-picking in-flight rows.
const now = Date.now();
return [{ json: { _run_start: now, _workflow_version: 'v5_stable' } }];

// ── Normalize + Validate Input ──
// CRITICAL: row_number is LOCKED here from Google Sheets native field.
// Never reconstruct or recalculate row_number downstream.

const item = $input.item.json;

const validSectionTypes = ['intro','accordion','faq','comparison','blog_post'];
const validFormats      = ['plain_text','json','markdown','html','wordpress_html'];
const validVoices       = ['professional','friendly','luxury','casual','authoritative'];

function norm(v, fallback) {
  return ((v ?? '').toString().toLowerCase().trim().replace(/[\s\-]+/g,'_')) || fallback;
}

function safeJson(val, fallback) {
  if (!val) return fallback;
  if (Array.isArray(val)) return val;
  if (typeof val === 'object' && val !== null) return Object.values(val);
  try { return JSON.parse(val); } catch {}
  return String(val).split(',').map(s => s.trim()).filter(Boolean);
}

function safeInt(val, fallback, min) {
  const n = parseInt(val);
  return isNaN(n) ? fallback : Math.max(min ?? 0, n);
}

function safeStr(val, fallback) {
  return ((val ?? '').toString().trim()) || fallback;
}

const langMap = {
  english:'en', spanish:'es', french:'fr', german:'de', italian:'it',
  portuguese:'pt', dutch:'nl', arabic:'ar', japanese:'ja', chinese:'zh',
  korean:'ko', russian:'ru', turkish:'tr', polish:'pl', hindi:'hi',
  hebrew:'he'
};

// ── LOCK row_number from Google Sheets ──
const rawRowNumber = item.row_number;
const rowNumber = typeof rawRowNumber === 'number'
  ? rawRowNumber
  : parseInt(rawRowNumber);

if (!rowNumber || isNaN(rowNumber) || rowNumber < 2) {
  throw new Error(
    `row_number invalid: got "${rawRowNumber}" (type: ${typeof rawRowNumber}). ` +
    `Google Sheets node must return row_number >= 2. ` +
    `Ensure the Sheets node has row_number enabled and Execute Once is OFF.`
  );
}

const sectionType = norm(item['Section Type'] || item['Page Type'], 'intro');
const language    = safeStr(item['Language'], 'English');
const langCode    = langMap[language.toLowerCase()] || 'en';
const outputFmt   = norm(item['Output Format'], 'markdown');
const brandVoice  = norm(item['Brand Voice'], 'professional');

return {
  json: {
    row_number:           rowNumber,
    row_id:               `row_${rowNumber}_${Date.now()}`,
    primary_keyword:      safeStr(item['Primary Keyword'], ''),
    page_type:            safeStr(item['Page Type'], ''),
    section_type:         validSectionTypes.includes(sectionType) ? sectionType : 'intro',
    word_count:           safeInt(item['Word Count'], 300, 50),
    keyword_count:        safeInt(item['Keyword Count'], 5, 1),
    min_keywords:         safeInt(item['Min Keywords Required'], 3, 1),
    language:             language,
    language_code:        langCode,
    country:              safeStr(item['Country / Location'] || item['Country'], 'United States'),
    topic_context:        safeStr(item['Topic Context'], ''),
    target_audience:      safeStr(item['Target Audience'], 'general audience'),
    content_goal:         safeStr(item['Content Goal'], 'inform readers'),
    required_topics:      safeJson(item['Required Topics'], []),
    forbidden_topics:     safeJson(item['Forbidden Topics'], []),
    brand_voice:          validVoices.includes(brandVoice) ? brandVoice : 'professional',
    brand_voice_example:  safeStr(item['Brand Voice Example'], ''),
    output_format:        validFormats.includes(outputFmt) ? outputFmt : 'markdown',
    existing_page_url:    safeStr(item['Existing Page URL'], ''),
    existing_page_text:   safeStr(item['Existing Page Content / Summary'], ''),
    existing_page_scraped: '',
    _scrape_source: 'pending',
    _phase: 'normalized'
  }
};

// ── Pass-through after Mark Processing ──
const normalized = $('03 Normalize + Validate Input').item.json;
return { json: { ...normalized, _phase: 'marked_processing' } };

// ── Extract Page Text (TRUE branch) ──
const normalized = $('03 Normalize + Validate Input').item.json;
const httpOut    = $input.item.json;

const isError = !!(
  httpOut?.error ||
  (typeof httpOut?.statusCode === 'number' && httpOut.statusCode >= 400)
);

let scrapedText = '';

if (!isError) {
  try {
    const raw = httpOut?.data
      || httpOut?.body
      || httpOut?.response?.body
      || httpOut?.text
      || (typeof httpOut === 'string' ? httpOut : '');

    const rawStr = typeof raw === 'string' ? raw : JSON.stringify(raw);

    scrapedText = rawStr
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
      .replace(/<!--[\s\S]*?-->/g, ' ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 6000);
  } catch (e) {
    scrapedText = '';
  }
}

const hasGoodScrape = scrapedText && scrapedText.length > 50;
const finalText     = hasGoodScrape
  ? scrapedText
  : (normalized.existing_page_text || '');

const scrapeSource = isError
  ? 'http_error'
  : hasGoodScrape
    ? 'scraped'
    : 'fallback_empty_response';

return {
  json: {
    ...normalized,
    existing_page_scraped: finalText,
    _scrape_source: scrapeSource,
    _scrape_error:  isError ? (httpOut?.error || `HTTP ${httpOut?.statusCode}`) : null,
    _phase: 'enriched'
  }
};

const normalized = $('03 Normalize + Validate Input').item.json;

return {
  json: {
    ...normalized,
    existing_page_scraped: normalized.existing_page_text || '',
    _scrape_source: 'no_url',
    _scrape_error: null,
    _phase: 'enriched'
  }
};

const items =
$json.tasks?.[0]?.result?.[0]?.items || [];

const organic = items
.filter(i => i.type === 'organic')
.slice(0,5)
.map(i => ({
  title: i.title,
  domain: i.domain
}));

const paa = items
.filter(i => i.type === 'people_also_ask')
.slice(0,5)
.map(i => i.title);

return [{
  json:{
    serp_organic: organic,
    people_also_ask: paa
  }
}];

function extractKeywords(nodeOutput) {
  const kws = [];
  if (!nodeOutput || typeof nodeOutput !== 'object') return kws;

  for (const task of (nodeOutput?.tasks || [])) {
    for (const result of (task?.result || [])) {
      for (const kw of (result?.items || [])) {
        if (!kw?.keyword || typeof kw.keyword !== 'string') continue;
        const kwStr = kw.keyword.trim();
        if (!kwStr || kwStr.length > 120) continue;
        kws.push({
          keyword:       kwStr,
          search_volume: kw.search_volume ?? kw.keyword_info?.search_volume ?? null,
          competition:   kw.competition ?? kw.keyword_info?.competition_level ?? null,
          cpc:           kw.cpc ?? kw.keyword_info?.cpc ?? null,
          intent:        kw.search_intent_info?.main_intent ?? kw.intent ?? 'informational',
          is_fallback:   false
        });
      }
    }
  }

  if (kws.length === 0 && nodeOutput?._flat && Array.isArray(nodeOutput?._items)) {
    for (const kw of nodeOutput._items) {
      if (!kw?.keyword || typeof kw.keyword !== 'string') continue;
      const kwStr = kw.keyword.trim();
      if (!kwStr || kwStr.length > 120) continue;
      kws.push({
        keyword:       kwStr,
        search_volume: kw.search_volume ?? kw.keyword_info?.search_volume ?? null,
        competition:   kw.competition ?? kw.keyword_info?.competition_level ?? null,
        cpc:           kw.cpc ?? kw.keyword_info?.cpc ?? null,
        intent:        kw.search_intent_info?.main_intent ?? kw.intent ?? 'informational',
        is_fallback:   false
      });
    }
  }

  return kws;
}

const inputData = $('08 Merge URL Branches').item.json;

if (!inputData?.row_number || !inputData?.primary_keyword) {
  throw new Error('Node 12: Cannot read inputData from Node 08. row_number or primary_keyword missing.');
}

let serpData = {
  serp_organic: [],
  people_also_ask: [],
  top_competitors: []
};

try {
  const parsedSerp = $('11b Parse SERP').item.json;
  serpData = {
    serp_organic: Array.isArray(parsedSerp?.serp_organic) ? parsedSerp.serp_organic : [],
    people_also_ask: Array.isArray(parsedSerp?.people_also_ask) ? parsedSerp.people_also_ask : [],
    top_competitors: Array.isArray(parsedSerp?.top_competitors) ? parsedSerp.top_competitors : []
  };
} catch (e) {}

let relatedRaw = {};
try {
  const items = $('09 DFS Related Keywords').all();
  if (items.length) {
    const raw = items[0].json;
    if (raw?.tasks) {
      relatedRaw = raw;
    } else if (Array.isArray(raw?.result)) {
      relatedRaw = { tasks: [{ result: raw.result }] };
    } else {
      const allItems = items.map(i => i.json).filter(Boolean);
      relatedRaw = { _flat: true, _items: allItems };
    }
  }
} catch(e) {}

const relatedKws = extractKeywords(relatedRaw);

const kwMap = new Map();
for (const kw of relatedKws) {
  const key = kw.keyword.toLowerCase();
  if (!kwMap.has(key)) kwMap.set(key, kw);
}

let allKeywords = Array.from(kwMap.values());
allKeywords.sort((a, b) => (b.search_volume || 0) - (a.search_volume || 0));

const minRequired = inputData.min_keywords || 3;
const pk = inputData.primary_keyword || 'travel';

if (allKeywords.length < minRequired) {
  const templates = [
    `best ${pk}`,`${pk} guide`,`${pk} tips`,`how to plan ${pk}`,`${pk} for beginners`,
    `${pk} cost`,`${pk} review`,`best time for ${pk}`,`${pk} for families`,`${pk} for couples`,
    `affordable ${pk}`,`top ${pk}`,`${pk} comparison`,`${pk} recommendations`,
    `${pk} pros and cons`,`${pk} checklist`,`${pk} 2025`,`why visit ${pk}`,
    `complete ${pk} guide`,`${pk} travel tips`
  ];

  for (const t of templates) {
    const key = t.toLowerCase();
    if (!kwMap.has(key)) {
      allKeywords.push({ keyword: t, search_volume: null, competition: null, cpc: null, intent: 'informational', is_fallback: true });
      kwMap.set(key, true);
    }
    if (allKeywords.filter(k => k.is_fallback).length >= 20) break;
  }
}

const intentGroups = { informational: [], commercial: [], transactional: [], navigational: [] };
for (const kw of allKeywords) {
  const intent = (kw.intent || 'informational').toLowerCase();
  if (intentGroups[intent]) intentGroups[intent].push(kw.keyword);
  else intentGroups.informational.push(kw.keyword);
}

const qPrefixes = new Set(['how','what','why','when','where','which','who','is','are','can','do','does','should']);
const questionKeywords = allKeywords.filter(kw => qPrefixes.has((kw.keyword.split(' ')[0] || '').toLowerCase())).map(kw => kw.keyword);

const coverageStats = {
  related_count: relatedKws.length,
  total_deduped: allKeywords.filter(k => !k.is_fallback).length,
  fallback_count: allKeywords.filter(k => k.is_fallback).length,
  fallback_applied: allKeywords.some(k => k.is_fallback),
  dfs_got_data: relatedKws.length > 0
};

return [{
  json: {
    ...inputData,
    keyword_research: {
      all_keywords: allKeywords,
      total_count: allKeywords.length,
      intent_groups: intentGroups,
      question_keywords: questionKeywords,
      question_clusters: {},
      serp_organic: serpData.serp_organic,
      people_also_ask: serpData.people_also_ask,
      top_competitors: serpData.top_competitors,
      coverage_stats: {
        ...coverageStats,
        serp_count: serpData.serp_organic.length,
        paa_count: serpData.people_also_ask.length,
        competitor_count: serpData.top_competitors.length
      }
    },
    _phase: 'keywords_aggregated'
  }
}];

// ── Parse + Validate LLM Keyword Decision ──

const inputData = $('12 Aggregate + Cluster + Fallback').item.json;
const allAvailableKeywords = inputData.keyword_research?.all_keywords || [];
const totalAvailable = allAvailableKeywords.length;
const minKw = inputData.min_keywords || 3;

function extractJson(raw) {
  if (!raw || typeof raw !== 'string') throw new Error('Empty LLM output');
  let cleaned = raw.trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  try { return JSON.parse(cleaned); } catch {}

  const objMatch = cleaned.match(/\{[\s\S]*\}/);
  if (objMatch) { try { return JSON.parse(objMatch[0]); } catch {} }

  const fixed = cleaned.replace(/,\s*([}\]])/g, '$1');
  try { return JSON.parse(fixed); } catch {}

  const arrMatch = cleaned.match(/\[[\s\S]*\]/);
  if (arrMatch) { try { return { selected_keywords: JSON.parse(arrMatch[0]) }; } catch {} }

  throw new Error('Cannot parse LLM JSON. Raw snippet: ' + raw.slice(0, 400));
}

const raw = $json?.message?.content
  || $json?.output?.[0]?.content?.[0]?.text
  || $json?.output?.[0]?.content
  || $json?.choices?.[0]?.message?.content
  || $json?.text
  || '';

if (!raw?.trim()) {
  throw new Error('LLM Keyword Decision returned empty output. Check prompt and token limit.');
}

let parsed;
try {
  parsed = extractJson(raw);
} catch(e) {
  parsed = {
    selected_keywords: [],
    keyword_mapping_by_section: {},
    selected_questions: [],
    excluded_keywords: [],
    search_intent: 'informational',
    confidence_score: 30,
    keyword_selection_reason: 'JSON parse failed — partial recovery applied.',
    reason: 'Parse failure',
    needs_review: true,
    needs_review_reason: `LLM output JSON parse failed: ${e.message}`
  };
}

if (!Array.isArray(parsed.selected_keywords))         parsed.selected_keywords = [];
if (!Array.isArray(parsed.selected_questions))         parsed.selected_questions = [];
if (!Array.isArray(parsed.excluded_keywords))          parsed.excluded_keywords = [];
if (typeof parsed.keyword_mapping_by_section !== 'object' || Array.isArray(parsed.keyword_mapping_by_section))
  parsed.keyword_mapping_by_section = {};
if (typeof parsed.confidence_score !== 'number')       parsed.confidence_score = 50;
parsed.confidence_score = Math.min(100, Math.max(0, Math.round(parsed.confidence_score)));
if (typeof parsed.search_intent !== 'string')          parsed.search_intent = 'informational';
parsed.keyword_selection_reason = (parsed.keyword_selection_reason || parsed.reason || '').trim();
if (typeof parsed.needs_review !== 'boolean')          parsed.needs_review = false;

parsed.selected_keywords = parsed.selected_keywords.map(kw => {
  if (typeof kw === 'string') {
    const match = allAvailableKeywords.find(k => k.keyword.toLowerCase() === kw.toLowerCase());
    return { keyword: kw.trim(), search_volume: match?.search_volume ?? null, competition: match?.competition ?? null, cpc: match?.cpc ?? null, intent: match?.intent ?? 'informational', is_fallback: match?.is_fallback ?? false, relevance_reason: '' };
  }
  if (typeof kw === 'object' && kw !== null && typeof kw.keyword === 'string') {
    return { keyword: kw.keyword.trim(), search_volume: typeof kw.search_volume === 'number' ? kw.search_volume : null, competition: kw.competition || null, cpc: typeof kw.cpc === 'number' ? kw.cpc : null, intent: kw.intent || 'informational', is_fallback: Boolean(kw.is_fallback), relevance_reason: (kw.relevance_reason || '').trim() };
  }
  return null;
}).filter(Boolean);

const seen = new Set();
parsed.selected_keywords = parsed.selected_keywords.filter(kw => {
  const k = kw.keyword.toLowerCase();
  if (seen.has(k)) return false;
  seen.add(k);
  return true;
});

const forbidden = inputData.forbidden_topics || [];
if (forbidden.length > 0) {
  const beforeCount = parsed.selected_keywords.length;
  parsed.selected_keywords = parsed.selected_keywords.filter(kw => {
    const kwl = kw.keyword.toLowerCase();
    return !forbidden.some(f => f && kwl.includes(f.toString().toLowerCase()));
  });
  const removed = beforeCount - parsed.selected_keywords.length;
  if (removed > 0) parsed.keyword_selection_reason += ` [SYSTEM: ${removed} keyword(s) force-removed — matched forbidden topic.]`;
}

const afterForbidden = parsed.selected_keywords.length;
if (afterForbidden < minKw) {
  const selectedSet = new Set(parsed.selected_keywords.map(k => k.keyword.toLowerCase()));
  const forbiddenSet = new Set(forbidden.map(f => f.toString().toLowerCase()));
  const candidates = allAvailableKeywords.filter(k => !selectedSet.has(k.keyword.toLowerCase())).filter(k => !forbiddenSet.has(k.keyword.toLowerCase())).sort((a, b) => { if (a.is_fallback !== b.is_fallback) return a.is_fallback ? 1 : -1; return (b.search_volume || 0) - (a.search_volume || 0); });
  const needed = minKw - afterForbidden;
  const backfilled = candidates.slice(0, needed).map(k => ({ ...k, relevance_reason: 'Auto-backfilled to meet minimum keyword requirement.' }));
  parsed.selected_keywords = [...parsed.selected_keywords, ...backfilled];
  if (backfilled.length > 0) parsed.keyword_selection_reason += ` [SYSTEM: ${backfilled.length} keyword(s) auto-backfilled to meet minimum of ${minKw}.]`;
}

const finalCount = parsed.selected_keywords.length;
const withVolume = parsed.selected_keywords.filter(k => k.search_volume && k.search_volume > 0).length;
const fallbackCount = parsed.selected_keywords.filter(k => k.is_fallback).length;
const fallbackRatio = finalCount > 0 ? fallbackCount / finalCount : 1;
const realKeywordsAvailable = allAvailableKeywords.filter(k => !k.is_fallback).length;

if (finalCount >= minKw) {
  if (parsed.confidence_score < 80) { parsed.confidence_score = 80; parsed.keyword_selection_reason += ' [SYSTEM: Score raised to 80 — minimum keyword count met.]'; }
} else {
  parsed.confidence_score = Math.min(parsed.confidence_score, 72);
}

if (fallbackRatio > 0.6) {
  if (realKeywordsAvailable === 0) { parsed.confidence_score = Math.min(parsed.confidence_score, 82); parsed.keyword_selection_reason += ' [SYSTEM: All keywords are fallback — DFS returned no data.]'; }
  else { parsed.confidence_score = Math.min(parsed.confidence_score, 74); parsed.keyword_selection_reason += ' [SYSTEM: Score capped — majority of keywords are fallback despite real keywords being available.]'; }
}

if (withVolume >= 5 && parsed.confidence_score >= 80) parsed.confidence_score = Math.min(100, parsed.confidence_score + 3);
parsed.confidence_score = Math.min(100, Math.max(0, Math.round(parsed.confidence_score)));

if (inputData.section_type === 'accordion') {
  const mapping = parsed.keyword_mapping_by_section;
  const expectedKeys = ['overview.why_visit','overview.best_for','overview.where_to_stay','things_to_do.top_attractions','things_to_do.nature_and_outdoors','things_to_do.food_and_nightlife','trip_planning.best_time_to_visit','trip_planning.getting_around','trip_planning.budget_and_costs'];
  const hasNestedFormat = expectedKeys.some(k => mapping[k] !== undefined);
  if (!hasNestedFormat) {
    const allSelected = parsed.selected_keywords.map(k => k.keyword);
    const chunkSize = Math.ceil(allSelected.length / expectedKeys.length);
    expectedKeys.forEach((key, i) => { mapping[key] = { keywords: allSelected.slice(i * chunkSize, (i + 1) * chunkSize), intent: 'informational' }; });
    parsed.keyword_selection_reason += ' [SYSTEM: Accordion mapping auto-rebuilt from flat format.]';
  }
}

const paaCount = inputData.keyword_research?.people_also_ask?.length || 0;
if (inputData.section_type === 'faq' && paaCount > 0 && parsed.selected_questions.length === 0) {
  parsed.selected_questions = inputData.keyword_research.people_also_ask.slice(0, 5).map(q => typeof q === 'string' ? q : (q.question || q.title || '')).filter(Boolean);
  parsed.keyword_selection_reason += ' [SYSTEM: FAQ questions auto-filled from People Also Ask data.]';
}

parsed.needs_review = parsed.confidence_score < 80;
if (parsed.needs_review && !parsed.needs_review_reason) parsed.needs_review_reason = `Confidence score ${parsed.confidence_score} < 80.`;
if (!parsed.needs_review) parsed.needs_review_reason = undefined;

parsed._keyword_stats = {
  total_available: totalAvailable,
  real_keywords_available: realKeywordsAvailable,
  min_required: minKw,
  selected_count: finalCount,
  with_volume: withVolume,
  fallback_count: fallbackCount,
  fallback_ratio: Math.round(fallbackRatio * 100) + '%',
  auto_backfilled: finalCount - afterForbidden
};

return [{ json: { ...inputData, llm_decision: parsed, _phase: 'keywords_decided' } }];

