const inputData = $('17 Build Content Brief').item.json;

let primarySearchVolume = 0;
try {
  primarySearchVolume = $('09 DFS Related Keywords').item.json?.tasks?.[0]?.result?.[0]?.search_volume || 0;
} catch(e) {}

const rawField = $json?.output?.[0]?.content?.[0]?.text;
let rawOutput = typeof rawField === 'object' && rawField !== null
  ? JSON.stringify(rawField)
  : (rawField ?? $json?.choices?.[0]?.message?.content ?? $json?.message?.content ?? $json?.content ?? '');

if (!rawOutput) throw new Error(`Node 24: Empty output. Full json keys: ${Object.keys($json || {}).join(', ')}`);

if (typeof rawOutput === 'object') {
  try { rawOutput = JSON.stringify(rawOutput); } catch { rawOutput = String(rawOutput); }
}
rawOutput = String(rawOutput).trim();
if (!rawOutput) throw new Error(`Content generation returned empty output for row ${inputData.row_number} (${inputData.section_type})`);

function tryParseJson(raw) {
  if (typeof raw !== 'string') raw = JSON.stringify(raw || '');
  const cleaned = raw.trim().replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();
  try { return JSON.parse(cleaned); } catch {}
  const objM = cleaned.match(/\{[\s\S]*\}/);
  if (objM) { try { return JSON.parse(objM[0]); } catch {} }
  const arrM = cleaned.match(/\[[\s\S]*\]/);
  if (arrM) { try { return JSON.parse(arrM[0]); } catch {} }
  try { return JSON.parse(cleaned.replace(/,\s*([}\]])/g, '$1')); } catch {}
  return null;
}

const sectionType = inputData.section_type;
const outputFormat = inputData.output_format;

let parsedContent = null;
let finalOutput = '';
let metaTitle = '';
let metaDesc = '';
let suggestedSlug = '';
let parseError = null;

if (['accordion','faq','comparison','blog_post'].includes(sectionType)) {
  parsedContent = tryParseJson(rawOutput);
  if (sectionType === 'faq' && parsedContent && !Array.isArray(parsedContent)) {
    if (Array.isArray(parsedContent.faqs)) parsedContent = parsedContent.faqs;
    else if (Array.isArray(parsedContent.questions)) parsedContent = parsedContent.questions;
    else if (Array.isArray(parsedContent.faq)) parsedContent = parsedContent.faq;
  }
  if (sectionType === 'faq' && Array.isArray(parsedContent)) finalOutput = JSON.stringify(parsedContent, null, 2);
  if (!parsedContent) { parseError = 'JSON parse failed — storing as raw text for review.'; parsedContent = { _raw: rawOutput, _parse_error: parseError }; }
}

switch (outputFormat) {
  case 'json': finalOutput = parsedContent ? JSON.stringify(parsedContent, null, 2) : rawOutput; break;
  case 'markdown':
    if (parsedContent && sectionType === 'blog_post') {
      const p = parsedContent;
      let md = `# ${p.title || inputData.primary_keyword}\n\n${p.intro || ''}\n\n`;
      for (const s of (p.sections || [])) { const tag = s.heading_level === 'h3' ? '###' : '##'; md += `${tag} ${s.heading}\n\n${s.content}\n\n`; }
      if ((p.faq || []).length > 0) { md += `## Frequently Asked Questions\n\n`; for (const q of p.faq) md += `### ${q.question}\n\n${q.answer}\n\n`; }
      md += `${p.conclusion || ''}`; finalOutput = md.trim();
    } else finalOutput = rawOutput;
    break;
  case 'html': case 'wordpress_html':
    if (parsedContent && sectionType === 'blog_post') {
      const p = parsedContent;
      let html = `<h1>${p.title || inputData.primary_keyword}</h1>\n<p>${p.intro || ''}</p>\n`;
      for (const s of (p.sections || [])) { const tag = s.heading_level || 'h2'; html += `<${tag}>${s.heading}</${tag}>\n<p>${s.content}</p>\n`; }
      if ((p.faq || []).length > 0) { html += `<h2>Frequently Asked Questions</h2>\n`; for (const q of p.faq) html += `<h3>${q.question}</h3>\n<p>${q.answer}</p>\n`; }
      html += `<p>${p.conclusion || ''}</p>`; finalOutput = html.trim();
    } else finalOutput = rawOutput;
    break;
  default: finalOutput = typeof parsedContent === 'object' && parsedContent ? JSON.stringify(parsedContent, null, 2) : rawOutput;
}

if (sectionType === 'blog_post' && parsedContent && !parsedContent._parse_error) {
  metaTitle = parsedContent.meta_title || '';
  metaDesc = parsedContent.meta_description || '';
  suggestedSlug = parsedContent.suggested_slug || '';
}

return { json: { ...inputData, primary_search_volume: primarySearchVolume, generated_content: parsedContent, final_output: finalOutput, meta_title: metaTitle, meta_description: metaDesc, suggested_slug: suggestedSlug, _content_raw: rawOutput, _content_parse_error: parseError, _phase: 'content_generated' } };

const d = $input.item.json;
const failures = [];
const warnings = [];

const output    = d.final_output || '';
const section   = d.section_type;
const forbidden = d.forbidden_topics || [];
const keywords = (d.llm_decision?.selected_keywords || []).map(k => typeof k?.keyword === 'string' ? k.keyword.toLowerCase() : '').filter(Boolean);

const wordCount = output.split(/\s+/).filter(Boolean).length;
const targetWC  = d.word_count || 300;

if (!output || output.trim().length < 50) failures.push('Content is empty or too short (< 50 chars).');

const wcRatio = wordCount / targetWC;
if (wcRatio < 0.15) failures.push(`Word count too low: ${wordCount} words (target: ${targetWC}, ratio: ${wcRatio.toFixed(2)}).`);
else if (wcRatio > 2.0) warnings.push(`Word count very high: ${wordCount} words (target: ${targetWC}).`);

const outputLower = output.toLowerCase();
const foundForbidden = forbidden.filter(f => f && outputLower.includes(f.toString().toLowerCase()));
if (foundForbidden.length > 0) failures.push(`Forbidden topic(s) found in content: ${foundForbidden.join(', ')}.`);

if (keywords.length > 0) {
  const foundKws = keywords.filter(kw => outputLower.includes(kw));
  const kwCoverage = foundKws.length / keywords.length;
  if (kwCoverage < 0.10) failures.push(`Low keyword coverage: only ${foundKws.length}/${keywords.length} keywords found (${(kwCoverage*100).toFixed(0)}%).`);
  else if (kwCoverage < 0.50) warnings.push(`Moderate keyword coverage: ${foundKws.length}/${keywords.length} (${(kwCoverage*100).toFixed(0)}%).`);
}

if (['accordion','faq','comparison','blog_post'].includes(section) && d._content_parse_error) failures.push(`JSON parse failed for ${section} section: ${d._content_parse_error}`);

if (section === 'faq') {
  const faqContent = d.generated_content;
  if (Array.isArray(faqContent) && faqContent.length < 3) failures.push(`FAQ has fewer than 3 questions (found: ${faqContent.length}).`);
  const paaCount = d.keyword_research?.people_also_ask?.length || 0;
  if (paaCount > 0 && Array.isArray(faqContent) && faqContent.length === 0) failures.push('People Also Ask data was available but no FAQ items were generated.');
}

if (section === 'blog_post') {
  const bp = d.generated_content;
  if (bp && !bp._parse_error) {
    if (!bp.title) warnings.push('Blog post missing title.');
    if (!bp.meta_title) warnings.push('Blog post missing meta_title.');
    if (!bp.meta_description) warnings.push('Blog post missing meta_description.');
    if (!Array.isArray(bp.sections) || bp.sections.length < 2) failures.push('Blog post has fewer than 2 sections.');
  }
}

if (d._content_parse_error) warnings.push(`Content parse issue: ${d._content_parse_error}`);

const preQcPassed = failures.length === 0;
const preQcSummary = [failures.length > 0 ? `FAILURES (${failures.length}): ${failures.join(' | ')}` : 'No failures.', warnings.length > 0 ? `WARNINGS (${warnings.length}): ${warnings.join(' | ')}` : ''].filter(Boolean).join(' /// ');

return { json: { ...d, pre_qc: { passed: preQcPassed, failures, warnings, summary: preQcSummary, word_count_actual: wordCount }, _phase: 'pre_qc_done' } };

