const inputData = $('24b Deterministic Pre-QC').item.json;

const rawQc = $json?.output?.[0]?.content?.[0]?.text || $json?.output?.[0]?.content || $json?.message?.content || $json?.choices?.[0]?.message?.content || '';

function tryParse(raw) {
  if (!raw || typeof raw !== 'string') return null;
  const cleaned = raw.trim().replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();
  try { return JSON.parse(cleaned); } catch {}
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) { try { return JSON.parse(match[0]); } catch {} }
  try { return JSON.parse(cleaned.replace(/,\s*([}\]])/g, '$1')); } catch {}
  return null;
}

let qcResult = tryParse(rawQc);
if (!qcResult) qcResult = { scores: {}, overall_score: 50, quality_passed: false, top_issues: ['QC parse failed'], quick_wins: [], keyword_coverage_feedback: '', brand_voice_feedback: '', content_summary: '', recommended_action: 'review', revision_notes: 'LLM QC output could not be parsed.' };

if (typeof qcResult.overall_score !== 'number') qcResult.overall_score = 50;
qcResult.overall_score = Math.max(0, Math.min(10, qcResult.overall_score));
if (typeof qcResult.quality_passed !== 'boolean') qcResult.quality_passed = qcResult.overall_score >= 7;
if (!Array.isArray(qcResult.top_issues)) qcResult.top_issues = [];
if (!Array.isArray(qcResult.quick_wins)) qcResult.quick_wins = [];

const preQc = inputData.pre_qc || {};
if (!preQc.passed) { qcResult.quality_passed = false; qcResult.top_issues = [...qcResult.top_issues, ...(preQc.failures || [])]; }

const finalStatus = qcResult.quality_passed ? 'Done' : 'Needs Review';

const qcSummary = [`Overall Score: ${qcResult.overall_score}/10`, `Status: ${qcResult.quality_passed ? 'PASSED' : 'FAILED'}`, qcResult.top_issues.length ? `Issues: ${qcResult.top_issues.join('; ')}` : 'No major issues detected.', qcResult.content_summary || ''].join(' | ');

const metaTitle = inputData.meta_title || `${inputData.primary_keyword} | ${inputData.content_goal}`;
const metaDesc = inputData.meta_description || `${(inputData.topic_context || '').slice(0, 140)}...`;
const slug = inputData.suggested_slug || inputData.primary_keyword.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'');

return { json: { ...inputData, qc_result: qcResult, quality_check_text: qcSummary, final_status: finalStatus, meta_title: metaTitle, meta_description: metaDesc, suggested_slug: slug, needs_review: !qcResult.quality_passed, needs_review_reason: qcResult.top_issues.join(' | ') || '', _phase: 'qc_complete' } };
